"use client"

import { FormEvent, useState } from "react"
import { useRouter } from "next/navigation"
import { signIn } from "next-auth/react"
import { ACCOUNT_PLAN_OPTIONS } from "@/lib/platform"

const roleCards = [
  {
    value: "CLIENT",
    title: "Sou cliente",
    description: "Quero acompanhar meu cao, acessar conteudos, assinar canais e evoluir com disciplina.",
  },
  {
    value: "TRAINER",
    title: "Sou adestrador",
    description: "Quero atender alunos, abrir meu canal, publicar conteudos e operar treinos com mais autoridade.",
  },
  {
    value: "VET",
    title: "Sou veterinario",
    description: "Quero orientar clientes, oferecer servicos, publicar guias de saude e participar dos canais.",
  },
] as const

export default function RegisterPage() {
  const router = useRouter()
  const [role, setRole] = useState<(typeof roleCards)[number]["value"]>("CLIENT")
  const [plan, setPlan] = useState<(typeof ACCOUNT_PLAN_OPTIONS)[number]["code"]>("FREE")
  const [name, setName] = useState("")
  const [email, setEmail] = useState("")
  const [password, setPassword] = useState("")
  const [phone, setPhone] = useState("")
  const [city, setCity] = useState("")
  const [state, setState] = useState("")
  const [message, setMessage] = useState("")
  const [loading, setLoading] = useState(false)

  const handleSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault()
    setLoading(true)
    setMessage("")

    const normalizedEmail = email.trim().toLowerCase()

    try {
      const res = await fetch("/api/register", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          name,
          email: normalizedEmail,
          password,
          phone,
          role,
          plan,
          city,
          state,
        }),
      })

      const data = await res.json()

      if (res.ok && data.success) {
        setMessage("Conta criada. Redirecionando para verificacao...")
        setName("")
        setEmail("")
        setPassword("")
        setPhone("")
        setCity("")
        setState("")
        const login = await signIn("credentials", { email: normalizedEmail, password, redirect: false })
        if (login?.error) {
          setMessage("Conta criada, mas o login automatico falhou. Entre manualmente.")
          return
        }
        router.push(plan === "FREE" ? "/verify" : `/verify?next=billing&plan=${plan}`)
        return
      }

      setMessage(data.message || "Erro ao criar usuario")
    } catch (error) {
      console.error(error)
      setMessage("Erro ao criar usuario")
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-[100svh] bg-[radial-gradient(circle_at_top,rgba(34,211,238,0.18),transparent_28%),linear-gradient(145deg,#020617,#0f172a_50%,#020617)] text-white">
      <div className="mx-auto flex min-h-[100svh] max-w-6xl flex-col gap-10 px-4 py-12 sm:px-6 lg:flex-row lg:items-center">
        <div className="flex-1 space-y-6">
          <span className="inline-flex items-center gap-2 rounded-full border border-cyan-300/20 bg-cyan-500/10 px-3 py-1 text-xs uppercase tracking-[0.28em] text-cyan-100">
            Onboarding disciplinado
          </span>
          <div className="space-y-4">
            <h1 className="max-w-2xl text-4xl font-bold leading-tight md:text-5xl">
              Entre na plataforma com o papel certo e um fluxo pronto para crescer.
            </h1>
            <p className="max-w-2xl text-lg text-slate-300">
              Cliente acompanha treino, calendario e conteudo do canal assinado. Adestradores e veterinarios entram
              com operacao, autoridade e espaco proprio para vender servicos e educar a comunidade.
            </p>
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            {roleCards.map((item) => {
              const active = role === item.value
              return (
                <button
                  key={item.value}
                  type="button"
                  onClick={() => setRole(item.value)}
                  className={`rounded-[24px] border p-5 text-left transition ${
                    active
                      ? "border-cyan-300/50 bg-cyan-500/15 shadow-lg shadow-cyan-500/15"
                      : "border-white/10 bg-white/5 hover:bg-white/10"
                  }`}
                >
                  <p className="text-lg font-semibold">{item.title}</p>
                  <p className="mt-2 text-sm text-slate-300">{item.description}</p>
                </button>
              )
            })}
          </div>
        </div>

        <div className="flex-1">
          <div className="mx-auto w-full max-w-xl rounded-[32px] border border-white/10 bg-white/8 p-8 shadow-2xl backdrop-blur-xl">
            <div className="mb-6">
              <p className="text-sm uppercase tracking-[0.2em] text-cyan-200/80">Cadastro</p>
              <h2 className="text-2xl font-semibold">Criar conta</h2>
              <p className="mt-2 text-sm text-slate-300">
                Escolha como quer entrar, defina o plano inicial e comece com a estrutura certa para o seu momento.
              </p>
            </div>

            <form className="flex flex-col gap-4" onSubmit={handleSubmit}>
              <div className="flex flex-col gap-2">
                <label className="text-sm text-slate-200/80">Tipo de conta</label>
                <select
                  value={role}
                  onChange={(e) => setRole(e.target.value as (typeof roleCards)[number]["value"])}
                  className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                >
                  <option value="CLIENT" className="text-black">
                    Cliente
                  </option>
                  <option value="TRAINER" className="text-black">
                    Adestrador
                  </option>
                  <option value="VET" className="text-black">
                    Veterinario
                  </option>
                </select>
              </div>

              <div className="flex flex-col gap-2">
                <label className="text-sm text-slate-200/80">Plano da conta</label>
                <div className="grid gap-3">
                  {ACCOUNT_PLAN_OPTIONS.map((item) => {
                    const active = plan === item.code
                    return (
                      <button
                        key={item.code}
                        type="button"
                        onClick={() => setPlan(item.code)}
                        className={`rounded-2xl border p-4 text-left transition ${
                          active
                            ? "border-cyan-300/50 bg-cyan-500/15 shadow-lg shadow-cyan-500/10"
                            : "border-white/10 bg-white/5 hover:bg-white/10"
                        }`}
                      >
                        <div className="flex items-center justify-between gap-4">
                          <div>
                            <p className="text-base font-semibold">{item.name}</p>
                            <p className="mt-1 text-sm text-slate-300">{item.description}</p>
                          </div>
                          <span className="text-sm font-semibold text-cyan-100">{item.priceLabel}</span>
                        </div>
                      </button>
                    )
                  })}
                </div>
              </div>

              <div className="flex flex-col gap-2">
                <label className="text-sm text-slate-200/80">Nome</label>
                <input
                  type="text"
                  placeholder="Seu nome"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  required
                  className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white placeholder:text-slate-400 focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                />
              </div>

              <div className="flex flex-col gap-2">
                <label className="text-sm text-slate-200/80">Email</label>
                <input
                  type="email"
                  placeholder="voce@exemplo.com"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white placeholder:text-slate-400 focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                />
              </div>

              <div className="flex flex-col gap-2">
                <label className="text-sm text-slate-200/80">Senha</label>
                <input
                  type="password"
                  placeholder="••••••••"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white placeholder:text-slate-400 focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                />
              </div>

              <div className="flex flex-col gap-2">
                <label className="text-sm text-slate-200/80">Telefone</label>
                <input
                  type="tel"
                  placeholder="+55 67 9xxxx-xxxx"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                  className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white placeholder:text-slate-400 focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                />
              </div>

              <div className="grid gap-4 md:grid-cols-2">
                <div className="flex flex-col gap-2">
                  <label className="text-sm text-slate-200/80">Cidade</label>
                  <input
                    type="text"
                    placeholder="Campo Grande"
                    value={city}
                    onChange={(e) => setCity(e.target.value)}
                    className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white placeholder:text-slate-400 focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                  />
                </div>

                <div className="flex flex-col gap-2">
                  <label className="text-sm text-slate-200/80">Estado</label>
                  <input
                    type="text"
                    placeholder="MS"
                    value={state}
                    onChange={(e) => setState(e.target.value.toUpperCase())}
                    maxLength={2}
                    className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white placeholder:text-slate-400 focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                  />
                </div>
              </div>

              <div className="rounded-2xl border border-emerald-300/15 bg-emerald-500/10 p-4 text-sm text-emerald-50">
                {plan === "FREE" ? (
                  <>
                    Entrada imediata no <strong>plano Free</strong>. Depois do cadastro voce confirma o email, completa
                    o perfil, cadastra ate 3 caes e participa do blog.
                  </>
                ) : (
                  <>
                    Seu cadastro reserva o plano <strong>{plan}</strong>. Depois do email confirmado, conclua a
                    assinatura para liberar forum, conteudos, agenda e treinos.
                  </>
                )}
              </div>

              <button
                type="submit"
                disabled={loading}
                className="mt-2 flex items-center justify-center gap-2 rounded-2xl bg-[linear-gradient(135deg,#06b6d4,#10b981)] px-4 py-3 font-semibold text-white shadow-lg shadow-cyan-500/20 transition hover:-translate-y-0.5 disabled:cursor-not-allowed disabled:opacity-60"
              >
                {loading ? "Criando conta..." : "Criar conta"}
              </button>
            </form>

            {message && <p className="mt-4 text-sm text-cyan-100">{message}</p>}
          </div>
        </div>
      </div>
    </div>
  )
}
